+            NewSI->getMetadata(LLVMContext::MD_DIAssignID));
+      } else {
+        NewSI->setMetadata(LLVMContext::MD_DIAssignID, NewID);
+      }
+      if (AATags)
+        NewSI->setAAMetadata(AATags);
