+            NewSI, nullptr, NewSI->getParent(), MemorySSA::Beginning);
+      } else {
+        if (auto *MD = dyn_cast<MemoryDef>(MSSAInsertPoint)) {
+          MemoryDef *DefToUse = LastDefMap.lookup(MD);
+          if (!DefToUse)
+            DefToUse = MD;
+          NewMemAcc = MSSAU.createMemoryDef(NewSI, DefToUse);
+          LastDefMap[MD] = cast<MemoryDef>(NewMemAcc);
+        } else {
+          NewMemAcc = MSSAU.createMemoryUse(NewSI,
+                                            cast<MemoryUse>(MSSAInsertPoint));
+        }
