+  void instructionDeleted(Instruction *I) const override {
+    SafetyInfo.removeInstruction(I);
+    MSSAU.removeMemoryAccess(I);
+  }
+
+  bool shouldDelete(Instruction *I) const override {
+    if (isa<LoadInst>(I))
+      return true;
+    if (isa<StoreInst>(I))
+      return CanInsertStoresInExitBlocks;
+    return false;
+  }
